@using sv_121d45ebad3e4750bd23e929b9a6c294.Services

<button class="channel-item @(IsActive ? "active" : "")" @onclick="() => OnSelect.InvokeAsync(Channel.Id)">
    <div class="channel-top">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-desc">@TruncateDescription(Channel.Description)</div>
    }
</button>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelect { get; set; }

    private static string TruncateDescription(string desc) =>
        desc.Length > 50 ? desc[..47] + "..." : desc;
}

.channel-item {
    display: block;
    width: 100%;
    text-align: left;
    padding: 10px 14px;
    border: none;
    background: none;
    cursor: pointer;
    border-radius: 6px;
    transition: background 0.1s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.1);
}

.channel-item.active {
    background: rgba(255, 255, 255, 0.18);
}

.channel-top {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 600;
    font-size: 14px;
    color: #e0e0e0;
}

.channel-item.active .channel-name {
    color: #fff;
}

.unread-badge {
    background: #e74c3c;
    color: #fff;
    font-size: 11px;
    font-weight: 700;
    min-width: 20px;
    height: 20px;
    border-radius: 10px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0 6px;
}

.channel-desc {
    font-size: 12px;
    color: #aaa;
    margin-top: 2px;
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
}

@using sv_121d45ebad3e4750bd23e929b9a6c294.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <nav class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnSelect="OnChannelSelected" />
        }
    </nav>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #2c3e50;
    color: #ecf0f1;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.sidebar-header h3 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
}

@using sv_121d45ebad3e4750bd23e929b9a6c294.Services

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageBubble Message="RootMessage" ShowActions="false" IsHighlighted="true" />
        </div>

        <div class="thread-replies">
            @if (Replies.Count == 0)
            {
                <p class="no-replies">No replies yet</p>
            }
            else
            {
