{"path": "/tmp/sv-121d45ebad3e4750bd23e929b9a6c294/Components/Chat/MessageArea.razor", "file_text": "@using sv_121d45ebad3e4750bd23e929b9a6c294.Services
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-area">
    <div class="area-header">
        @if (Channel is not null)
        {
            <h3># @Channel.Name</h3>
            <span class="area-desc">@Channel.Description</span>
        }
    </div>

    <div class="message-list" @ref="messageListRef" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages...</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageBubble Message="msg"
                           ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                           OnOpenThread="OnOpenThread"
                           OnReact="OnReact" />
        }
    </div>

    <MessageInput OnSubmit="OnSendMessage" />
</div>

@code {
    private ElementReference messageListRef;
    private DotNetObjectReference<MessageArea>? dotNetRef;
    private IJSObjectReference? jsModule;

    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private int GetThreadReplyCount(int messageId)
    {
        var summary = ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);
        return summary?.ReplyCount ?? 0;
    }

    private async Task HandleScroll()
    {
        if (!HasMoreMessages || IsLoadingMore) return;

        // Check if scrolled near top via JS interop
        if (jsModule is not null)
        {
            var scrollTop = await jsModule.InvokeAsync<double>("getScrollTop", messageListRef);
            if (scrollTop < 50)
            {
                await OnLoadMore.InvokeAsync();
            }
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-121d45ebad3e4750bd23e929b9a6c294/Components/Chat/MessageArea.razor.js");
            await ScrollToBottom();
        }
    }

    private async Task ScrollToBottom()
    {
        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
        }
    }

    public async ValueTask DisposeAsync()
    {
        dotNetRef?.Dispose();
        if (jsModule is not null)
        {
            await jsModule.DisposeAsync();
        }
    }
}
"}

