toolArgs.file_text:
.message-bubble {
    position: relative;
    padding: 8px 14px;
    border-radius: 6px;
    transition: background 0.1s;
}

.message-bubble:hover {
    background: #f5f5f5;
}

.message-bubble.highlighted {
    background: #eef3fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 14px;
    color: #1a1a1a;
}

.timestamp {
    font-size: 12px;
    color: #888;
}

.message-content {
    font-size: 14px;
    line-height: 1.45;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    border: 1px solid #ddd;
    border-radius: 12px;
    font-size: 13px;
    background: #f8f8f8;
    cursor: default;
}

.thread-link {
    background: none;
    border: none;
    color: #4a76a8;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 4px;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -12px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
    padding: 2px;
    z-index: 5;
}

.action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    font-size: 13px;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background: #f0f0f0;
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 180px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
    padding: 4px;
    z-index: 6;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 18px;
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

