@using sv_121d45ebad3e4750bd23e929b9a6c294.Services

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageBubble Message="RootMessage" ShowActions="false" IsHighlighted="true" />
        </div>

        <div class="thread-replies">
            @if (Replies.Count == 0)
            {
                <p class="no-replies">No replies yet</p>
            }
            else
            {
                @foreach (var reply in Replies)
                {
                    <MessageBubble Message="reply" ShowActions="false" />
                }
            }
        </div>

        <MessageInput Placeholder="Reply in thread..."
                      ButtonLabel="Reply"
                      OnSubmit="OnReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h4 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 18px;
    cursor: pointer;
    color: #888;
    width: 28px;
    height: 28px;
    border-radius: 4px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.close-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root {
    padding: 8px 4px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 4px;
}

.no-replies {
    text-align: center;
    color: #999;
    font-size: 14px;
    padding: 24px;
}

