namespace sv_121d45ebad3e4750bd23e929b9a6c294.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_121d45ebad3e4750bd23e929b9a6c294.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Team Chat</PageTitle>

<div class="chat-layout">
    <div class="sidebar-panel">
        <ChannelSidebar Channels="channels"
                        SelectedChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-panel @(isThreadOpen ? "" : "expanded")">
        <MessageArea Channel="selectedChannel"
                     Messages="messages"
                     ThreadSummaries="threadSummaries"
                     IsLoadingMore="isLoadingMore"
                     HasMoreMessages="hasMoreMessages"
                     OnLoadMore="LoadMoreMessages"
                     OnSendMessage="SendMessage"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction" />
    </div>

    @if (isThreadOpen)
    {
        <div class="thread-panel-container">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];

    private int selectedChannelId;
    private Channel? selectedChannel;
    private int messagesSkip;
    private bool hasMoreMessages = true;
    private bool isLoadingMore;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messagesSkip = 0;
        hasMoreMessages = true;
        isThreadOpen = false;

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messagesSkip = messages.Count;
        hasMoreMessages = messages.Count >= PageSize;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);

        // Update local unread count
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannelId, messagesSkip, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;

        messages.InsertRange(0, older);
        messagesSkip += older.Count;

        BuildThreadSummaries();
        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            selectedChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary count in the main view
        var existing = threadSummaries.FirstOrDefault(t => t.RootMessageId == threadRootMessage.Id);
        if (existing is not null)
        {
            threadSummaries.Remove(existing);
            threadSummaries.Add(existing with { ReplyCount = existing.ReplyCount + 1, LastReplyAt = DateTime.Now });
        }
        else
        {
            threadSummaries.Add(new ThreadSummary(threadRootMessage.Id, 1, DateTime.Now));
        }
    }

    private async Task HandleReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        // Optimistic update on local message
        var msg = messages.FirstOrDefault(m => m.Id == reaction.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == reaction.Emoji);
            if (existing is not null)
            {
                existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(reaction.Emoji, ["You"]));
            }
        }
    }

    private void BuildThreadSummaries()
    {
        // Build thread summaries from messages that have replies
        var replyGroups = messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value);

        threadSummaries = replyGroups
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();
    }
}

